#include <Arduino.h>
#include <Wire.h>
#include <U8g2lib.h>
#include <vector>
#include "mbedtls/base64.h"

#define OLED_SDA 1
#define OLED_SCL 2
#define OLED_RST 47
#define SCREEN_W 128
#define SCREEN_H 32
#define BTN_SCROLL_UP 14
#define BTN_SCROLL_DOWN 21
#define BTN_SCROLL_LEFT 40
#define BTN_SCROLL_RIGHT 41

static constexpr uint32_t BUTTON_DEBOUNCE_MS = 35;
static constexpr int H_SCROLL_STEP = 32;
static constexpr uint32_t OLED_CLEAR_SETTLE_MS = 8;

U8G2_SSD1305_128X32_NONAME_F_HW_I2C u8g2(U8G2_R0, OLED_RST);

struct Button {
  uint8_t pin;
  bool lastStable = HIGH;
  bool lastRead = HIGH;
  unsigned long lastChange = 0;

  void begin(uint8_t p) {
    pin = p;
    pinMode(pin, INPUT_PULLUP);
    lastStable = digitalRead(pin);
    lastRead = lastStable;
    lastChange = millis();
  }

  bool fell() {
    bool reading = digitalRead(pin);
    if (reading != lastRead) {
      lastChange = millis();
      lastRead = reading;
    }
    if ((millis() - lastChange) >= BUTTON_DEBOUNCE_MS && reading != lastStable) {
      lastStable = reading;
      return lastStable == LOW;
    }
    return false;
  }
};

struct Block {
  int width;
  int height;
  const char* b64;
  std::vector<uint8_t> bytes;
  bool valid;
};

Button btnUp;
Button btnDown;
Button btnLeft;
Button btnRight;

int currentBlock = 0;
int currentX = 0;
int validCount = 0;

