bool decodeBase64ToBytes(const char* encoded, std::vector<uint8_t>& out) {
  size_t required = 0;
  int rc = mbedtls_base64_decode(
    nullptr, 0, &required,
    reinterpret_cast<const unsigned char*>(encoded),
    strlen(encoded)
  );
  if (rc != MBEDTLS_ERR_BASE64_BUFFER_TOO_SMALL && rc != 0) return false;
  if (required == 0) return false;

  out.assign(required, 0);
  size_t written = 0;
  rc = mbedtls_base64_decode(
    out.data(), out.size(), &written,
    reinterpret_cast<const unsigned char*>(encoded),
    strlen(encoded)
  );
  if (rc != 0) return false;
  if (written != out.size()) out.resize(written);
  return true;
}

void invertBitmapBytes(std::vector<uint8_t>& bytes) {
  for (uint8_t& b : bytes) b = ~b;
}

void drawTwoLines(const String& l1, const String& l2) {
  u8g2.clearBuffer();
  u8g2.setFont(u8g2_font_6x10_tf);
  u8g2.drawStr(0, 12, l1.c_str());
  u8g2.drawStr(0, 28, l2.c_str());
  u8g2.sendBuffer();
}

void clearOledFrame() {
  u8g2.clearBuffer();
  u8g2.sendBuffer();
  delay(OLED_CLEAR_SETTLE_MS);
}

int firstValidBlock() {
  int total = sizeof(kBlocks) / sizeof(kBlocks[0]);
  for (int i = 0; i < total; i++) {
    if (kBlocks[i].valid) return i;
  }
  return -1;
}

int nextValidBlock(int from) {
  int total = sizeof(kBlocks) / sizeof(kBlocks[0]);
  for (int i = from + 1; i < total; i++) {
    if (kBlocks[i].valid) return i;
  }
  return from;
}

int prevValidBlock(int from) {
  for (int i = from - 1; i >= 0; i--) {
    if (kBlocks[i].valid) return i;
  }
  return from;
}

int maxXFor(const Block& b) {
  return max(0, b.width - SCREEN_W);
}

void clampViewer() {
  if (currentBlock < 0 || !kBlocks[currentBlock].valid) currentBlock = firstValidBlock();
  if (currentBlock < 0) return;
  int maxX = maxXFor(kBlocks[currentBlock]);
  if (currentX < 0) currentX = 0;
  if (currentX > maxX) currentX = maxX;
}

void renderCurrentBlock() {
  clampViewer();
  if (currentBlock < 0) return;
  const Block& b = kBlocks[currentBlock];
  clearOledFrame();
  u8g2.clearBuffer();
  u8g2.setDrawColor(1);
  u8g2.drawXBMP(-currentX, 0, b.width, b.height, b.bytes.data());
  u8g2.sendBuffer();
  Serial.printf("[OLED] block %d x=%d maxX=%d\n", currentBlock + 1, currentX, maxXFor(b));
}

void moveUp() {
  int prev = prevValidBlock(currentBlock);
  if (prev != currentBlock) {
    currentBlock = prev;
    currentX = 0;
  }
}

void moveDown() {
  int next = nextValidBlock(currentBlock);
  if (next != currentBlock) {
    currentBlock = next;
    currentX = 0;
  }
}

void moveLeft() {
  if (currentX > 0) {
    currentX -= H_SCROLL_STEP;
    if (currentX < 0) currentX = 0;
    return;
  }

  int prev = prevValidBlock(currentBlock);
  if (prev != currentBlock) {
    currentBlock = prev;
    currentX = maxXFor(kBlocks[currentBlock]);
  }
}

void moveRight() {
  int maxX = maxXFor(kBlocks[currentBlock]);
  if (currentX < maxX) {
    currentX += H_SCROLL_STEP;
    if (currentX > maxX) currentX = maxX;
    return;
  }

  int next = nextValidBlock(currentBlock);
  if (next != currentBlock) {
    currentBlock = next;
    currentX = 0;
  }
}

void setup() {
  Serial.begin(115200);
  delay(700);
  Serial.println();
  Serial.println("=== OLED Bitmap Demo ===");

  btnUp.begin(BTN_SCROLL_UP);
  btnDown.begin(BTN_SCROLL_DOWN);
  btnLeft.begin(BTN_SCROLL_LEFT);
  btnRight.begin(BTN_SCROLL_RIGHT);

  Wire.begin(OLED_SDA, OLED_SCL);
  // 100 kHz is intentionally conservative for breadboard/flying-wire OLED tests.
  Wire.setClock(100000);
  u8g2.setI2CAddress(0x3C * 2);
  u8g2.begin();
  u8g2.setContrast(12);

  drawTwoLines("Bitmap demo", "Decoding...");

  int total = sizeof(kBlocks) / sizeof(kBlocks[0]);
  for (int i = 0; i < total; i++) {
    bool ok = decodeBase64ToBytes(kBlocks[i].b64, kBlocks[i].bytes);
    int expected = ((kBlocks[i].width + 7) / 8) * kBlocks[i].height;
    kBlocks[i].valid = ok && (int)kBlocks[i].bytes.size() == expected;
    if (!kBlocks[i].valid) {
      Serial.printf("[WARN] skip block %d size=%u expected=%d\n",
                    i + 1, (unsigned)kBlocks[i].bytes.size(), expected);
    } else {
      validCount++;
    }
  }

  drawTwoLines("Bitmap demo", "Rendering...");
  delay(600);

  if (validCount == 0) {
    drawTwoLines("No valid block", "check base64");
    Serial.println("[ERR] no valid bitmap blocks");
    return;
  }

  currentBlock = firstValidBlock();
  currentX = 0;
  renderCurrentBlock();
  Serial.printf("[OK] viewer ready, valid blocks=%d\n", validCount);
}

void loop() {
  bool changed = false;
  if (btnUp.fell()) {
    Serial.println("[BTN] UP");
    moveUp();
    changed = true;
  }
  if (btnDown.fell()) {
    Serial.println("[BTN] DOWN");
    moveDown();
    changed = true;
  }
  if (btnLeft.fell()) {
    Serial.println("[BTN] LEFT");
    moveLeft();
    changed = true;
  }
  if (btnRight.fell()) {
    Serial.println("[BTN] RIGHT");
    moveRight();
    changed = true;
  }
  if (changed) renderCurrentBlock();
  delay(20);
}
